changeSet.sql:
INSERT INTO sub_category (id, name, translation_key, category_id)
SELECT nextval('sequence_generator'), 'Kommunikation', 'jaynaApp.document.main.communication', id FROM category WHERE entity_name = 'document'
ON CONFLICT DO NOTHING;

INSERT INTO sub_category (id, name, translation_key, category_id)
SELECT nextval('sequence_generator'), 'Finanzen & Versicherungen', 'jaynaApp.document.main.finances-insurance', id FROM category WHERE entity_name = 'document'
ON CONFLICT DO NOTHING;

INSERT INTO sub_category (id, name, translation_key, category_id)
SELECT nextval('sequence_generator'), 'Energie & Versorgung', 'jaynaApp.document.main.energy-utilities', id FROM category WHERE entity_name = 'document'
ON CONFLICT DO NOTHING;

INSERT INTO sub_category_group (id, name, translation_key, sub_category_id)
SELECT nextval('sequence_generator'), 'Rechnungen', 'jaynaApp.document.group.accounting', id FROM sub_category WHERE name = 'Finanzen & Versicherungen'
ON CONFLICT DO NOTHING;

INSERT INTO sub_category_group (id, name, translation_key, sub_category_id)
SELECT nextval('sequence_generator'), 'Bankwesen', 'jaynaApp.document.group.banking', id FROM sub_category WHERE name = 'Finanzen & Versicherungen'
ON CONFLICT DO NOTHING;

INSERT INTO group_type (id, name, translation_key, sub_category_group_id)
SELECT nextval('sequence_generator'), 'Rechnung', 'jaynaApp.document.type.invoice', id FROM sub_category_group WHERE name = 'Rechnungen'
ON CONFLICT DO NOTHING;

INSERT INTO group_type (id, name, translation_key, sub_category_group_id)
SELECT nextval('sequence_generator'), 'Kontoauszug', 'jaynaApp.document.type.account-statement', id FROM sub_category_group WHERE name = 'Bankwesen'
ON CONFLICT DO NOTHING;
